const express = require('express');
const axios = require('axios');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json({ limit: '5mb' }));
app.use(express.urlencoded({ extended: true, limit: '5mb' }));

app.post('/proxy', async (req, res) => {
    const targetUrl = req.query.url || req.body.targetUrl;

    if (!targetUrl) {
        return res.status(400).send('Target URL is required. Provide in "url" query or "targetUrl" body field.');
    }

    try {
        const axiosConfig = {
            method: req.method,
            url: targetUrl,
            headers: { ...req.headers },
            data: req.body,
            timeout: 15000,
            validateStatus: () => true
        };

        delete axiosConfig.headers.host;
        delete axiosConfig.headers['content-length'];
        delete axiosConfig.headers.connection;
        delete axiosConfig.headers['accept-encoding'];

        const upstreamResponse = await axios(axiosConfig);

        res.status(upstreamResponse.status);
        
        for (const key in upstreamResponse.headers) {
            const lowerCaseKey = key.toLowerCase();
            if (!['transfer-encoding', 'connection', 'content-encoding'].includes(lowerCaseKey)) {
                res.setHeader(key, upstreamResponse.headers[key]);
            }
        }
        
        res.send(upstreamResponse.data);

    } catch (error) {
        if (error.response) {
            res.status(error.response.status).send(error.response.data);
        } else if (error.request) {
            res.status(504).send('Gateway Timeout: No response received from the target URL.');
        } else {
            res.status(500).send(`Proxy Service Error: ${error.message}`);
        }
    }
});

app.get('/health', (req, res) => {
    res.status(200).send('OK');
});

app.listen(PORT, () => {
    console.log(`Webhook proxy service listening on port ${PORT}`);
});